172→/// Parse a journal markdown file into a JournalEntry.
173→pub fn parse_markdown(content: &str) -> Result<JournalEntry, String> {
174→    // Split frontmatter from body
175→    let (frontmatter, body) = split_frontmatter(content)?;
176→
177→    // Parse YAML frontmatter
178→    let date = extract_yaml_field(&frontmatter, "date")
179→        .ok_or("Missing date in frontmatter")?;
180→    let generated_at = extract_yaml_field(&frontmatter, "generated_at")
181→        .unwrap_or_default();
182→    let stats = parse_frontmatter_only(content)?;
183→
184→    // Parse body into repo sections and other work
185→    let (repos, other_work) = parse_body(&body);
186→
187→    Ok(JournalEntry {
188→        date,
189→        generated_at,
190→        repos,
191→        other_work,
192→        stats,
193→    })
