196→fn split_frontmatter(content: &str) -> Result<(String, String), String> {
197→    let content = content.trim();
198→    if !content.starts_with("---") {
199→        return Err("No frontmatter found".to_string());
200→    }
201→    let rest = &content[3..];
202→    let end = rest.find("---").ok_or("Unterminated frontmatter")?;
203→    let frontmatter = rest[..end].trim().to_string();
204→    let body = rest[end + 3..].trim().to_string();
205→    Ok((frontmatter, body))
206→}
