208→fn extract_yaml_field(yaml: &str, field: &str) -> Option<String> {
209→    for line in yaml.lines() {
210→        let line = line.trim();
211→        if let Some(rest) = line.strip_prefix(&format!("{}:", field)) {
212→            let value = rest.trim().trim_matches('"').trim_matches('\'');
213→            if !value.is_empty() {
214→                return Some(value.to_string());
215→            }
216→        }
217→    }
218→    None
219→}
