221→fn parse_frontmatter_only(content: &str) -> Result<JournalStats, String> {
222→    let (frontmatter, _) = split_frontmatter(content)?;
223→
224→    let lines_changed = extract_yaml_field(&frontmatter, "lines_changed")
225→        .and_then(|v| v.parse().ok())
226→        .unwrap_or(0);
227→    let sessions = extract_yaml_field(&frontmatter, "sessions")
228→        .and_then(|v| v.parse().ok())
229→        .unwrap_or(0);
230→    let prs = extract_yaml_field(&frontmatter, "prs")
231→        .and_then(|v| v.parse().ok())
232→        .unwrap_or(0);
233→    let ai_authored_pct = extract_yaml_field(&frontmatter, "ai_authored_pct")
234→        .and_then(|v| v.parse().ok())
235→        .unwrap_or(0);
236→    let tokens = extract_yaml_field(&frontmatter, "tokens")
237→        .and_then(|v| v.parse().ok())
238→        .unwrap_or(0);
239→
240→    Ok(JournalStats {
241→        lines_changed,
242→        sessions,
243→        prs,
244→        ai_authored_pct,
245→        tokens,
246→    })
247→}
