249→fn parse_body(body: &str) -> (Vec<RepoSection>, Vec<String>) {
250→    let mut repos = Vec::new();
251→    let mut other_work = Vec::new();
252→    let mut current_repo: Option<RepoSection> = None;
253→    let mut in_prs = false;
254→    let mut in_other_work = false;
255→
256→    for line in body.lines() {
257→        let trimmed = line.trim();
258→
259→        // H2 heading = repo name or "Other Work"
260→        if let Some(heading) = trimmed.strip_prefix("## ") {
261→            // Save previous repo
262→            if let Some(repo) = current_repo.take() {
263→                repos.push(repo);
264→            }
265→            in_prs = false;
266→
267→            if heading == "Other Work" {
268→                in_other_work = true;
269→                continue;
270→            }
271→
272→            in_other_work = false;
273→            current_repo = Some(RepoSection {
274→                name: heading.to_string(),
275→                lines_added: 0,
276→                lines_removed: 0,
277→                accomplishments: Vec::new(),
278→                pull_requests: Vec::new(),
279→            });
280→            continue;
281→        }
282→
283→        // H3 heading = "Pull Requests" subsection
284→        if trimmed.starts_with("### Pull Requests") {
285→            in_prs = true;
286→            continue;
287→        }
288→
289→        // Lines diff stats: _+716 -131_
290→        if trimmed.starts_with("_+") && trimmed.ends_with('_') {
291→            if let Some(ref mut repo) = current_repo {
292→                let inner = &trimmed[1..trimmed.len() - 1];
293→                let parts: Vec<&str> = inner.split_whitespace().collect();
294→                if parts.len() == 2 {
295→                    repo.lines_added = parts[0].trim_start_matches('+').parse().unwrap_or(0);
296→                    repo.lines_removed = parts[1].trim_start_matches('-').parse().unwrap_or(0);
297→                }
298→            }
299→            continue;
300→        }
301→
302→        // Bullet points
303→        if let Some(bullet_content) = trimmed.strip_prefix("- ") {
304→            if in_other_work {
305→                other_work.push(bullet_content.to_string());
306→            } else if in_prs {
307→                if let Some(ref mut repo) = current_repo {
308→                    if let Some(pr) = parse_pr_line(bullet_content) {
309→                        repo.pull_requests.push(pr);
310→                    }
311→                }
312→            } else if let Some(ref mut repo) = current_repo {
313→                repo.accomplishments.push(bullet_content.to_string());
314→            }
315→        }
316→    }
317→
318→    // Don't forget last repo
319→    if let Some(repo) = current_repo {
320→        repos.push(repo);
321→    }
322→
323→    (repos, other_work)
324→}
