413→pub(crate) fn current_date() -> String {
414→    let now = std::time::SystemTime::now()
415→        .duration_since(std::time::UNIX_EPOCH)
416→        .unwrap_or_default()
417→        .as_secs();
418→    format_unix_date(now as i64)
419→}
420→
421→pub fn format_unix_date(secs: i64) -> String {
422→    // Simple date formatting from unix timestamp
423→    let days = secs / 86400;
424→    let (year, month, day) = days_to_ymd(days);
425→    format!("{:04}-{:02}-{:02}", year, month, day)
426→}
427→
428→pub(crate) fn subtract_days(date: &str, n: i64) -> String {
429→    // Parse YYYY-MM-DD, subtract n days, return YYYY-MM-DD
430→    let parts: Vec<i64> = date.split('-').filter_map(|p| p.parse().ok()).collect();
431→    if parts.len() != 3 {
432→        return date.to_string();
433→    }
434→    let total_days = ymd_to_days(parts[0], parts[1], parts[2]) - n;
435→    let (y, m, d) = days_to_ymd(total_days);
436→    format!("{:04}-{:02}-{:02}", y, m, d)
437→}
438→
439→fn ymd_to_days(year: i64, month: i64, day: i64) -> i64 {
440→    let mut days: i64 = 0;
441→    for y in 1970..year {
442→        days += if is_leap(y) { 366 } else { 365 };
443→    }
444→    let month_lengths = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
445→    for m in 1..month {
446→        days += month_lengths[m as usize];
447→        if m == 2 && is_leap(year) {
448→            days += 1;
449→        }
450→    }
451→    days + day - 1
452→}
453→
454→fn days_to_ymd(mut days: i64) -> (i64, i64, i64) {
455→    let mut year = 1970;
456→    loop {
457→        let year_days = if is_leap(year) { 366 } else { 365 };
458→        if days < year_days {
459→            break;
460→        }
461→        days -= year_days;
462→        year += 1;
463→    }
464→    let month_lengths = if is_leap(year) {
465→        [31, 29, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
466→    } else {
467→        [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
468→    };
469→    let mut month = 1;
470→    for &ml in &month_lengths {
471→        if days < ml {
472→            break;
473→        }
474→        days -= ml;
475→        month += 1;
476→    }
477→    (year, month, days + 1)
478→}
479→
480→fn is_leap(y: i64) -> bool {
481→    y % 4 == 0 && (y % 100 != 0 || y % 400 == 0)
482→}
