import { useState, useEffect, type FormEvent } from "react";
import { X, Eye, EyeOff } from "lucide-react";
import {
  useAppSettingsQuery,
  useSaveAppSettingsMutation,
  type AppSettings,
} from "../../hooks/use-tauri-query";

interface SettingsViewProps {
  onClose: () => void;
}

export function SettingsView({ onClose }: SettingsViewProps) {
  const { data: settings, isLoading } = useAppSettingsQuery();
  const saveMutation = useSaveAppSettingsMutation();
  const [apiKey, setApiKey] = useState("");
  const [worktreeBasePath, setWorktreeBasePath] = useState("");
  const [showApiKey, setShowApiKey] = useState(false);
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    if (settings) {
      setApiKey(settings.anthropic_api_key ?? "");
      setWorktreeBasePath(settings.worktree_base_path ?? "");
    }
  }, [settings]);

  function handleSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const nextSettings: AppSettings = {
      anthropic_api_key: apiKey.trim() || null,
      worktree_base_path: worktreeBasePath.trim() || null,
    };
    saveMutation.mutate(nextSettings, {
      onSuccess: () => {
        setSaved(true);
        setTimeout(() => setSaved(false), 2000);
      },
    });
  }

  return (
    <div className="fixed inset-0 z-30 flex items-center justify-center bg-black/50 p-4">
      <form
        onSubmit={handleSubmit}
        className="w-full max-w-lg rounded-lg border border-border bg-bg-overlay shadow-2xl"
      >
        <div className="flex items-center border-b border-border-subtle px-4 py-3">
          <div className="flex-1">
            <h3 className="text-sm font-semibold text-fg">Settings</h3>
            <p className="mt-0.5 text-xs text-fg-muted">App configuration</p>
          </div>
          <button
            type="button"
            onClick={onClose}
            className="flex h-7 w-7 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
            title="Close settings"
          >
            <X size={14} />
          </button>
        </div>

        {isLoading ? (
          <div className="px-4 py-8 text-center text-xs text-fg-subtle">
            Loading settings...
          </div>
        ) : (
          <div className="space-y-5 px-4 py-4">
            <label className="block text-xs text-fg-muted">
              Anthropic API key
              <p className="mb-1 text-[11px] text-fg-subtle">
                Used for semantic review. Falls back to ANTHROPIC_API_KEY env var if empty.
              </p>
              <div className="relative">
                <input
                  type={showApiKey ? "text" : "password"}
                  value={apiKey}
                  onChange={(e) => setApiKey(e.target.value)}
                  placeholder="sk-ant-..."
                  autoComplete="off"
                  autoCorrect="off"
                  autoCapitalize="off"
                  spellCheck={false}
                  className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 pr-9 text-sm text-fg outline-none transition-colors placeholder:text-fg-subtle focus:border-accent"
                />
                <button
                  type="button"
                  onClick={() => setShowApiKey(!showApiKey)}
                  className="absolute right-2 top-1/2 -translate-y-1/2 text-fg-subtle hover:text-fg"
                  tabIndex={-1}
                >
                  {showApiKey ? <EyeOff size={14} /> : <Eye size={14} />}
                </button>
              </div>
            </label>

            <label className="block text-xs text-fg-muted">
              Worktree base path
              <p className="mb-1 text-[11px] text-fg-subtle">
                Base directory for new worktrees. Leave empty to use repo-relative paths.
              </p>
              <input
                value={worktreeBasePath}
                onChange={(e) => setWorktreeBasePath(e.target.value)}
                placeholder="/Users/me/Projects/wt"
                autoComplete="off"
                autoCorrect="off"
                autoCapitalize="off"
                spellCheck={false}
                className="mt-1 w-full rounded border border-border bg-bg-raised px-3 py-2 text-sm text-fg outline-none transition-colors placeholder:text-fg-subtle focus:border-accent"
              />
            </label>

            {saveMutation.error && (
              <div className="rounded bg-red-bg px-3 py-2 text-xs text-red">
                {saveMutation.error.message}
              </div>
            )}
          </div>
        )}

        <div className="flex items-center justify-end gap-2 border-t border-border-subtle px-4 py-3">
          {saved && (
            <span className="text-xs text-green">Saved</span>
          )}
          <button
            type="button"
            onClick={onClose}
            className="rounded border border-border px-3 py-2 text-xs text-fg-muted transition-colors hover:border-border-hover hover:text-fg"
          >
            Cancel
          </button>
          <button
            type="submit"
            disabled={saveMutation.isPending}
            className="rounded bg-accent px-3 py-2 text-xs font-medium text-white transition-colors hover:bg-accent-hover disabled:cursor-not-allowed disabled:opacity-60"
          >
            {saveMutation.isPending ? "Saving..." : "Save"}
          </button>
        </div>
      </form>
    </div>
  );
}

