        .and_then(|v| v.parse().ok())
        .unwrap_or(0);
    let ai_authored_pct = extract_yaml_field(&frontmatter, "ai_authored_pct")
        .and_then(|v| v.parse().ok())
        .unwrap_or(0);
    let tokens = extract_yaml_field(&frontmatter, "tokens")
        .and_then(|v| v.parse().ok())
        .unwrap_or(0);

    Ok(JournalStats {
        lines_changed,
        sessions,
        prs,
        ai_authored_pct,
        tokens,
    })
}

fn parse_body(body: &str) -> (Vec<RepoSection>, Vec<String>) {
    let mut repos = Vec::new();
    let mut other_work = Vec::new();
    let mut current_repo: Option<RepoSection> = None;
    let mut in_prs = false;
    let mut in_other_work = false;

    for line in body.lines() {
        let trimmed = line.trim();

        // H2 heading = repo name or "Other Work"
        if let Some(heading) = trimmed.strip_prefix("## ") {
            // Save previous repo
            if let Some(repo) = current_repo.take() {
                repos.push(repo);
            }
            in_prs = false;

            if heading == "Other Work" {
                in_other_work = true;
                continue;
            }

            in_other_work = false;
            current_repo = Some(RepoSection {
                name: heading.to_string(),
                lines_added: 0,
                lines_removed: 0,
                accomplishments: Vec::new(),
                pull_requests: Vec::new(),
            });
            continue;
        }

        // H3 heading = "Pull Requests" subsection
        if trimmed.starts_with("### Pull Requests") {
            in_prs = true;
            continue;
        }

        // Lines diff stats: _+716 -131_
        if trimmed.starts_with("_+") && trimmed.ends_with('_') {
            if let Some(ref mut repo) = current_repo {
                let inner = &trimmed[1..trimmed.len() - 1];
                let parts: Vec<&str> = inner.split_whitespace().collect();
                if parts.len() == 2 {
                    repo.lines_added = parts[0].trim_start_matches('+').parse().unwrap_or(0);
                    repo.lines_removed = parts[1].trim_start_matches('-').parse().unwrap_or(0);
                }
            }
            continue;
        }

        // Bullet points
        if let Some(bullet_content) = trimmed.strip_prefix("- ") {
            if in_other_work {
                other_work.push(bullet_content.to_string());
            } else if in_prs {
                if let Some(ref mut repo) = current_repo {
                    if let Some(pr) = parse_pr_line(bullet_content) {
                        repo.pull_requests.push(pr);
                    }
                }
            } else if let Some(ref mut repo) = current_repo {
                repo.accomplishments.push(bullet_content.to_string());
            }
        }
    }

    // Don't forget last repo
    if let Some(repo) = current_repo {
        repos.push(repo);
    }

    (repos, other_work)
}

/// Parse a PR line like: **Settings page rebuild** #142 — merged
fn parse_pr_line(line: &str) -> Option<JournalPR> {
    // Pattern: **title** #number — status
    let bold_start = line.find("**")?;
    let bold_end = line[bold_start + 2..].find("**")? + bold_start + 2;
    let title = line[bold_start + 2..bold_end].to_string();

    let rest = &line[bold_end + 2..];
    let hash_pos = rest.find('#')?;
    let after_hash = &rest[hash_pos + 1..];

    // Find the number (digits until non-digit)
    let num_end = after_hash.find(|c: char| !c.is_ascii_digit()).unwrap_or(after_hash.len());
    let number: u64 = after_hash[..num_end].parse().ok()?;

    // Find status after — or -
    let status = if let Some(dash_pos) = rest.find('—').or_else(|| rest.find(" - ")) {
        let s = rest[dash_pos..].trim_start_matches('—').trim_start_matches(" - ").trim();
        s.to_string()
    } else {
        "open".to_string()
    };

    Some(JournalPR {
        title,
        number,
        status,
        additions: 0,
        deletions: 0,
        url: String::new(),
    })
}

/// Render a JournalEntry as a markdown string.
pub fn render_markdown(entry: &JournalEntry) -> String {
    let mut out = String::new();

    // Frontmatter
    out.push_str("---\n");
    out.push_str(&format!("date: {}\n", entry.date));
    out.push_str(&format!("generated_at: {}\n", entry.generated_at));

    // Repos list
    out.push_str("repos:\n");
    for repo in &entry.repos {
        out.push_str(&format!("  - {}\n", repo.name));
    }

    // Stats
    out.push_str("stats:\n");
    out.push_str(&format!("  lines_changed: {}\n", entry.stats.lines_changed));
    out.push_str(&format!("  sessions: {}\n", entry.stats.sessions));
    out.push_str(&format!("  prs: {}\n", entry.stats.prs));
    out.push_str(&format!("  ai_authored_pct: {}\n", entry.stats.ai_authored_pct));
    out.push_str(&format!("  tokens: {}\n", entry.stats.tokens));
    out.push_str("---\n\n");

    // Repo sections
    for repo in &entry.repos {
        out.push_str(&format!("## {}\n", repo.name));
        out.push_str(&format!("_+{} -{}_ \n\n", repo.lines_added, repo.lines_removed));

        for item in &repo.accomplishments {
            out.push_str(&format!("- {}\n", item));
        }

        if !repo.pull_requests.is_empty() {
            out.push_str("\n### Pull Requests\n");
            for pr in &repo.pull_requests {
                out.push_str(&format!("- **{}** #{} — {}\n", pr.title, pr.number, pr.status));
            }
        }

        out.push('\n');
    }

    // Other work
    if !entry.other_work.is_empty() {
        out.push_str("## Other Work\n");
        for item in &entry.other_work {
            out.push_str(&format!("- {}\n", item));
        }
    }

    out
}

pub(crate) fn current_date() -> String {
    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();
    format_unix_date(now as i64)
}

pub fn format_unix_date(secs: i64) -> String {
    // Simple date formatting from unix timestamp
    let days = secs / 86400;
    let (year, month, day) = days_to_ymd(days);
    format!("{:04}-{:02}-{:02}", year, month, day)
}

pub(crate) fn subtract_days(date: &str, n: i64) -> String {
    // Parse YYYY-MM-DD, subtract n days, return YYYY-MM-DD
    let parts: Vec<i64> = date.split('-').filter_map(|p| p.parse().ok()).collect();
    if parts.len() != 3 {
        return date.to_string();
    }
    let total_days = ymd_to_days(parts[0], parts[1], parts[2]) - n;
    let (y, m, d) = days_to_ymd(total_days);
    format!("{:04}-{:02}-{:02}", y, m, d)
}

fn ymd_to_days(year: i64, month: i64, day: i64) -> i64 {
    let mut days: i64 = 0;
    for y in 1970..year {
        days += if is_leap(y) { 366 } else { 365 };
    }
    let month_lengths = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
    for m in 1..month {
        days += month_lengths[m as usize];
        if m == 2 && is_leap(year) {
            days += 1;
        }
    }
    days + day - 1
}

fn days_to_ymd(mut days: i64) -> (i64, i64, i64) {
    let mut year = 1970;
    loop {
        let year_days = if is_leap(year) { 366 } else { 365 };
        if days < year_days {
            break;
        }
        days -= year_days;
        year += 1;
    }
    let month_lengths = if is_leap(year) {
        [31, 29, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
    } else {
        [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
    };
    let mut month = 1;
    for &ml in &month_lengths {
        if days < ml {
            break;
        }
        days -= ml;
        month += 1;
    }
    (year, month, days + 1)
}

fn is_leap(y: i64) -> bool {
    y % 4 == 0 && (y % 100 != 0 || y % 400 == 0)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn roundtrip_markdown() {
        let entry = JournalEntry {
            date: "2026-03-20".to_string(),
            generated_at: "2026-03-20T17:42:00Z".to_string(),
            repos: vec![RepoSection {
                name: "entire-app".to_string(),
                lines_added: 716,
                lines_removed: 131,
                accomplishments: vec![
                    "Rebuilt settings page as a modal dialog".to_string(),
                    "Fixed terminal resize handle drag".to_string(),
                ],
                pull_requests: vec![JournalPR {
                    title: "Settings page rebuild".to_string(),
                    number: 142,
                    status: "merged".to_string(),
                    additions: 312,
                    deletions: 89,
                    url: String::new(),
                }],
            }],
            other_work: vec!["Led sprint planning".to_string()],
            stats: JournalStats {
                lines_changed: 847,
                sessions: 4,
                prs: 3,
                ai_authored_pct: 68,
                tokens: 12300,
            },
        };

        let md = render_markdown(&entry);
        let parsed = parse_markdown(&md).unwrap();

        assert_eq!(parsed.date, "2026-03-20");
        assert_eq!(parsed.repos.len(), 1);
        assert_eq!(parsed.repos[0].name, "entire-app");
        assert_eq!(parsed.repos[0].lines_added, 716);
        assert_eq!(parsed.repos[0].accomplishments.len(), 2);
        assert_eq!(parsed.repos[0].pull_requests.len(), 1);
        assert_eq!(parsed.repos[0].pull_requests[0].number, 142);
        assert_eq!(parsed.other_work.len(), 1);
        assert_eq!(parsed.stats.lines_changed, 847);
    }

    #[test]
    fn parse_pr_line_works() {
        let pr = parse_pr_line("**Fix terminal resize** #141 — merged").unwrap();
        assert_eq!(pr.title, "Fix terminal resize");
        assert_eq!(pr.number, 141);
        assert_eq!(pr.status, "merged");
    }

    #[test]
    fn subtract_days_works() {
        assert_eq!(subtract_days("2026-03-20", 1), "2026-03-19");
        assert_eq!(subtract_days("2026-03-01", 1), "2026-02-28");
        assert_eq!(subtract_days("2026-01-01", 1), "2025-12-31");
    }

    #[test]
    fn parse_empty_body() {
        let (repos, other) = parse_body("");
        assert!(repos.is_empty());
        assert!(other.is_empty());
    }
}

